import torch
import torch.nn as nn
import torch.nn.functional as F

# Functional approach (stateless)
def relu(z: float) -> float:
    x = torch.tensor(z, dtype=torch.float32)
    return float(F.relu(x).item())

# Module approach (stateful, used inside nn.Sequential / nn.Module)
class ReLUDemo(nn.Module):
    def __init__(self):
        super().__init__()
        self.relu = nn.ReLU()

    def forward(self, x: torch.Tensor) -> torch.Tensor:
        return self.relu(x)

# Demonstrating autograd through ReLU
def relu_with_gradient(z: float):
    x = torch.tensor(z, dtype=torch.float32, requires_grad=True)
    y = F.relu(x)
    y.backward()  # compute dy/dx
    return float(y.item()), float(x.grad.item()) if x.grad is not None else 0.0
